# Bicep: custom role with management group AssignableScopes
// Deployed at management group scope
targetScope = 'managementGroup'

resource platformVMOperator 'Microsoft.Authorization/roleDefinitions@2022-04-01' = {
  name: guid('platform-vm-operator', managementGroup().id)
  properties: {
    roleName: 'Platform VM Operator'
    description: 'Start/restart VMs across all corp subscriptions'
    type: 'CustomRole'
    permissions: [
      {
        actions: [
          'Microsoft.Compute/virtualMachines/read'
          'Microsoft.Compute/virtualMachines/start/action'
          'Microsoft.Compute/virtualMachines/restart/action'
          'Microsoft.Compute/virtualMachines/deallocate/action'
          'Microsoft.Resources/subscriptions/resourceGroups/read'
          'Microsoft.Authorization/*/read'
        ]
        notActions: []
        dataActions: []
        notDataActions: []
      }
    ]
    // AssignableScopes must include the deployment scope
    assignableScopes: [ managementGroup().id ]
  }
}

# Terraform: management group scoped role
resource "azurerm_role_definition" "platform_vm_operator" {
  name  = "Platform VM Operator"
  scope = "/providers/Microsoft.Management/managementGroups/corp"

  permissions {
    actions = [
      "Microsoft.Compute/virtualMachines/read",
      "Microsoft.Compute/virtualMachines/start/action",
      "Microsoft.Compute/virtualMachines/restart/action",
    ]
    not_actions = []
  }

  assignable_scopes = ["/providers/Microsoft.Management/managementGroups/corp"]
}

# Scenario: role shared across production and staging subscriptions
# Both subscriptions are siblings under the same MG — use MG scope

# Option A: list both subscriptions explicitly
$role.AssignableScopes = @(
    '/subscriptions/prod-sub-id'
    '/subscriptions/staging-sub-id'
)
# Downside: must update when adding more environments

# Option B: use their shared parent MG
$role.AssignableScopes = @(
    '/providers/Microsoft.Management/managementGroups/app-team-mg'
)
# Upside: new environments (canary, preview) automatically included

# When to keep per-subscription scopes:
# - Roles that are deliberately environment-specific
#   (e.g. a 'Production Deployer' that should never appear in dev)
# - Roles using resource group scope for strict isolation

# Check which subscriptions a custom role is currently assignable in
$role = Get-AzRoleDefinition -Name 'App Team Deployer'
foreach ($scope in $role.AssignableScopes) {
    if ($scope -match 'managementGroups/(.+)') {
        Write-Host "MG: $($Matches[1]) — covers all child subscriptions"
        Get-AzManagementGroupSubscription -GroupId $Matches[1] |
            ForEach-Object { Write-Host "  Sub: $($_.DisplayName)" }
    } elseif ($scope -match 'subscriptions/([^/]+)$') {
        $sub = Get-AzSubscription -SubscriptionId $Matches[1]
        Write-Host "Sub: $($sub.Name)"
    }
}

# Audit: find custom roles with AssignableScopes set to root '/' (overly broad)
Get-AzRoleDefinition | Where-Object {
    $_.IsCustom -and $_.AssignableScopes -contains '/'
} | Select-Object Name, Description

# Find custom roles with no assignments (candidates for scope review or deletion)
$customRoles = Get-AzRoleDefinition | Where-Object { $_.IsCustom }
foreach ($role in $customRoles) {
    $assignments = @()
    foreach ($scope in $role.AssignableScopes) {
        $assignments += Get-AzRoleAssignment -RoleDefinitionId $role.Id -Scope $scope `
            -ErrorAction SilentlyContinue
    }
    [PSCustomObject]@{
        Name = $role.Name
        AssignableScopes = $role.AssignableScopes -join '; '
        AssignmentCount = $assignments.Count
        Recommendation = if ($assignments.Count -eq 0) { 'Review for deletion' } else { 'Active' }
    }
} | Sort-Object AssignmentCount | Format-Table -AutoSize

# Report: custom roles per scope level
Get-AzRoleDefinition | Where-Object { $_.IsCustom } | ForEach-Object {
    $highestScope = $_.AssignableScopes | ForEach-Object {
        if ($_ -eq '/') { 0 }
        elseif ($_ -match 'managementGroups') { 1 }
        elseif ($_ -match '^/subscriptions/[^/]+$') { 2 }
        elseif ($_ -match 'resourceGroups') { 3 }
        else { 4 }
    } | Measure-Object -Minimum | Select-Object -ExpandProperty Minimum
    [PSCustomObject]@{ Name=$_.Name; ScopeLevel=@('Root','MG','Sub','RG','Resource')[$highestScope] }
} | Group-Object ScopeLevel | Select-Object Name, Count
